sys_script_include.script:
var discordNotificationAlt = Class.create();
discordNotificationAlt.prototype = {
        initialize: function() {
            this.webhookURL = gs.getProperty('x_1759267_wrm.discord.webhook_url_alt');
        },
        sendMessage: function(message, emoji) {
            if (!this.webhookURL) {
                gs.warn('Discord webhook URL not configured. Check system property.');
                return false;
            }
            try {
                var request = new sn_ws.RESTMessageV2();
                request.setEndpoint(this.webhookURL);
                request.setHttpMethod('POST');
                request.setRequestHeader('Content-Type', 'application/json');
                var payload = {
                    content: (emoji ? emoji + ' ' : '') + message
                };
                request.setRequestBody(JSON.stringify(payload));
                var response = request.execute();
                var httpStatus = response.getStatusCode();
                if (httpStatus == 200 || httpStatus == 204) {
                    gs.info('Discord notification sent successfully');
                    return true;
                } else {
                    gs.error('Discord notification failed with status: ' + httpStatus);
                    return false;
                }
            } catch (ex) {
                gs.error('Error sending Discord notification: ' + ex.message);
                return false;
			}

            },

            type: 'discordNotificationAlt'
        };
